// Generate excerpt from content
const content = $('Final Edit').first().json.final_article;
const title = $('Process Request').first().json.title;

// Create excerpt from first few sentences
const sentences = content.split(/[.!?]+/).filter(s => s.trim().length > 10);
const excerpt = sentences.slice(0, 2).join('. ') + '.';

// Clean up excerpt
const cleanExcerpt = excerpt
  .replace(/\n/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 160); // WordPress excerpt limit

return {
  json: {
    excerpt: cleanExcerpt,
    message: 'Excerpt generated successfully',
    nextStep: 'wordpress_publishing'
  }
};

// Real WordPress API Integration
const content = $('Final Edit').first().json.final_article;
const title = $('Title Refinement').first().json.refined_title;
const excerpt = $('Generate Excerpt').first().json.excerpt;
const keywords = $('Process Request').first().json.keywords;

// WordPress API configuration
const wordpressConfig = {
  baseUrl: 'https://www.tax4us.co.il/wp-json/wp/v2',
  authToken: $credentials.wordpressAuthToken, // Store in n8n credentials
  apiKey: $credentials.wordpressApiKey // Store in n8n credentials
};

// Prepare post data according to WordPress REST API schema
const postData = {
  title: { raw: title },
  content: { raw: content },
  excerpt: { raw: excerpt },
  status: 'draft', // Start with draft for safety
  comment_status: 'open',
  ping_status: 'open',
  format: 'standard'
};

// Add categories if available
if (keywords.includes('tax planning')) {
  postData.categories = [1]; // Default category ID
}

// Add tags based on keywords
const tagNames = keywords.filter(k => k.length > 3);
if (tagNames.length > 0) {
  postData.tags = tagNames.map(tag => tag.toLowerCase().replace(/\s+/g, '-'));
}

try {
  // Make real WordPress API call
  const response = await fetch(`${wordpressConfig.baseUrl}/posts`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${wordpressConfig.authToken}`,
      'X-N8N-API-KEY': wordpressConfig.apiKey
    },
    body: JSON.stringify(postData)
  });

  if (!response.ok) {
    throw new Error(`WordPress API error: ${response.status} ${response.statusText}`);
  }

  const wordpressData = await response.json();

  return {
    json: {
      success: true,
      postId: wordpressData.id,
      title: wordpressData.title.rendered,
      content: wordpressData.content.rendered,
      excerpt: wordpressData.excerpt.rendered,
      status: wordpressData.status,
      url: wordpressData.link,
      editUrl: wordpressData.link.replace('/?p=', '/wp-admin/post.php?post=') + '&action=edit',
      wordCount: content.split(' ').length,
      keywords: keywords,
      timestamp: new Date().toISOString(),
      message: 'Content published to WordPress successfully',
      nextStep: 'completion'
    }
  };

} catch (error) {
  console.error('WordPress API Error:', error);

  // Fallback: return simulated data with error flag
  return {
    json: {
      success: false,
      error: true,
      errorMessage: error.message,
      postId: 'wp-fallback-' + Date.now(),
      title: title,
      content: content,
      excerpt: excerpt,
      status: 'draft',
      url: `https://www.tax4us.co.il/blog/${title.toLowerCase().replace(/\s+/g, '-')}`,
      wordCount: content.split(' ').length,
      keywords: keywords,
      timestamp: new Date().toISOString(),
      message: 'WordPress publishing failed - content saved locally',
      fallback: true,
      nextStep: 'completion'
    }
  };
}

// Final response for Tax4Us WordPress agent
const requestData = $('Process Request').first().json;
const wordpressData = $input.first().json;

const finalResponse = {
  success: wordpressData.success,
  message: wordpressData.success ? 
    'Tax4Us WordPress Content Agent completed successfully' : 
    'Tax4Us WordPress Content Agent completed with fallback',
  data: {
    title: requestData.title,
    keywords: requestData.keywords,
    topic: requestData.topic,
    wordCount: wordpressData.wordCount,
    wordpressUrl: wordpressData.url,
    wordpressEditUrl: wordpressData.editUrl,
    status: wordpressData.status,
    postId: wordpressData.postId,
    error: wordpressData.error || false,
    errorMessage: wordpressData.errorMessage || null,
    fallback: wordpressData.fallback || false
  },
  timestamp: new Date().toISOString(),
  agent: 'Tax4Us WordPress Agent - Real Integration',
  version: '2.1'
};

return { json: finalResponse };
